import{_ as i,c as e,o as p,ae as o}from"./chunks/framework.BvcDoAct.js";const m=JSON.parse('{"title":"edhiii boi","description":"","frontmatter":{},"headers":[],"relativePath":"zh-cn/Management2Extra/01_TalkAboutBMSG/03_EdhiiiBoi.md","filePath":"zh-cn/Management2Extra/01_TalkAboutBMSG/03_EdhiiiBoi.md"}'),t={name:"zh-cn/Management2Extra/01_TalkAboutBMSG/03_EdhiiiBoi.md"};function r(h,a,S,n,d,s){return p(),e("div",null,[...a[0]||(a[0]=[o('<p>Talk about BMSG - 03</p><h1 id="edhiii-boi" tabindex="-1">edhiii boi <a class="header-anchor" href="#edhiii-boi" aria-label="Permalink to &quot;edhiii boi&quot;">​</a></h1><h3 id="通过日高先生的言行意识到-自由的背后伴随着责任" tabindex="-1">通过日高先生的言行意识到“自由的背后伴随着责任” <a class="header-anchor" href="#通过日高先生的言行意识到-自由的背后伴随着责任" aria-label="Permalink to &quot;通过日高先生的言行意识到“自由的背后伴随着责任”&quot;">​</a></h3><p><em>edhiii boi：2007年1月18日出生，兵库县出身</em><br><br><br> ————在BMSG POSSE与SKY-HI一起活动，你有什么感受？</p><p>作为edhiii boi出道的时候，日高先生会来录音棚指导我，但出道一段时间后，就不再一起进录音棚了。所以POSSE的活动开始后，又能一起在录音棚里做歌，真的非常开心。</p><p>————在这个过程中，你再次感受到SKY-HI厉害之处是什么？</p><p>首先是他写歌词的速度，还有歌词里蕴含的多重含义。我觉得特别厉害的是，他不会刻意去说明“这句歌词其实是这个意思”，而是像埋了很多小机关一样，让人自己去体会。</p><p>还有就是，录音时的take次数非常少。很干脆地唱完一小节就立刻从录音室出来，那种感觉真的很帅。</p><p>————你觉得BMSG POSSE的活动，对edhiii boi个人的活动带来了哪些正面的影响？</p><p>在以POSSE的身份参加各种音乐节的过程中，能和日高先生一起站上舞台让我很开心，也让我更有自信。和平时的演出不同，当我随意往旁边一看，身边有我最信任的“老大”和伙伴们在，就会自然地产生自信。我觉得这样的经验也影响到了今年「BMSG FES&#39;24」的表演。</p><p>————在「BMSG FES&#39;24」中，你是从场馆的PA控制台登场的。</p><p>原本是打算从观众席入口登场的，但我无论如何都想从PA控制台登场。在我提出这个想法的时候，日高先生对我说：“绝对这样更好，就这么来吧”，帮我坚定了想法。结果，我成为出演者中和粉丝距离最近的人，可以对视、一起分享快乐，我觉得真的很好，非常感谢他。</p><p>————一年一度、BMSG艺人齐聚一堂的「BMSG FES」，对你来说是一个怎样的地方？</p><p>虽然平时我也经常会去看日高先生、BE:FIRST或者其他BMSG艺人的演出，但大家一起表演是一年一次。和一年前相比，每个人的想法肯定都有变化，RUI、TAIKI、KANON的心态也一定和去年完全不同。尤其是KANON，去年「BMSG FES」的时候才刚以BMSG练习生的身份被介绍，而今年则是以一名独立艺人的意识来参加。</p><p>所以在准备开始之前，我其实有点无法想象这会是一个什么样的音乐节。但在总彩排（最终彩排）的时候，一下子就觉得特别开心，当下就想“这一定会是个很有意思的音乐节”。而且也让我强烈觉得，能成为BMSG MARINE的一员真的太好了。</p><h3 id="和shota一起度过的时间成为了我的宝物" tabindex="-1">和Shota一起度过的时间成为了我的宝物 <a class="header-anchor" href="#和shota一起度过的时间成为了我的宝物" aria-label="Permalink to &quot;和Shota一起度过的时间成为了我的宝物&quot;">​</a></h3><p>————我觉得BMSG MARINE的《Memoria》展现了edhiii boi作为歌手的新魅力。</p><p>这都要感谢制作人Aile The Shota。我们一起构思旋律，在录音时他也给我做了很多指导。制作《Memoria》的那段时间，我的精神状态其实挺低落的，甚至会变得不想一个人在夜里待着，但Shota会带我去吃饭，在私下生活上也帮了我很多。</p><p>不仅仅是创作出《Memoria》这首歌，那段和Shota一起度过的时间，对我来说也成了宝物。感觉正是连同这些故事在内，才完成了《Memoria》这首作品。</p><p>————所以才会觉得能在MARINE真的很好。</p><p>真的这么觉得。多亏了Shota，我不再感到孤单，也不会再有那种晚上一个人想往外跑的感觉了，真的只有满满的感激。</p><p>————「BMSG FES&#39;24」第二天结束后，你在Instagram发了一篇长文。简单来说，是“希望大家跟着我走”的内容，当时为什么会发那篇文章？</p><p>其实原本是打算在第一天前一天，只发一篇关于《Memoria》的内容。我花了三四个小时把文章写好，准备发到Instagram的时候却删掉了。这是我的坏习惯，本来应该先复制再删除的，但我一按复制就马上把文字删掉了（笑）。结果其实没有复制成功，不管怎么粘贴都出不来，我当时就想“完了！”，立刻给Shota发LINE求助，结果他说“明天很早，今天就先放弃吧”。于是就决定等三天活动结束后，在一个合适的时机再发。</p><p>另外，这次音乐节里我负责MC的时间，只有《GALAXY》前奏那一小段。我原本想在那时候说出类似Instagram里写的那些话，但考虑到歌曲本身的氛围，如果说太热血的话感觉会有点不搭。所以最后还是决定找个更冷静的方式来表达。</p><p>结果第一天结束后，我收到了比预想中还要多的好评，通过私信等渠道不断传来。我就觉得“要在大家的热情还没冷却之前，把自己的想法说出来比较好”，于是赶紧重新写了文章，在第二天结束后发了出去。</p><p>————11月将举办「THE GAME CENTER」，有什么期待吗？</p><p>我运动神经真的很差，所以其实没什么特别期待的（笑）。大概跟RYUHEI差不多不擅长运动吧。现在还完全不知道会做什么项目，可能还是要看具体内容。</p><p>————有擅长的项目吗？</p><p>羽毛球吧。像排球这种我就特别不擅长。我会努力不拖大家后腿的（笑）。</p><h3 id="在旁守护着你-你就按自己想要的方式去做-是bmsg的风格" tabindex="-1">“在旁守护着你，你就按自己想要的方式去做”是BMSG的风格 <a class="header-anchor" href="#在旁守护着你-你就按自己想要的方式去做-是bmsg的风格" aria-label="Permalink to &quot;“在旁守护着你，你就按自己想要的方式去做”是BMSG的风格&quot;">​</a></h3><p>————什么时候会感受到作为BMSG艺人的优势？</p><p>在感到孤单的时候，有人会陪在身边。比如我说“想做这样的音乐”，就会有人回应“那我们一起做吧”；还有肚子饿的时候，会有像哥哥一样的人带我去吃饭，这对我来说真的很重要。</p><p>————加入BMSG之后，你觉得最庆幸的一点是什么？</p><p>当然，也有那种由别人铺好路，然后告诉你“按这个顺序走就一定能成功”的方式，这种我觉得也是正确的。但BMSG的方式是，“我们会在旁边守着你，剩下的你就按自己想走的路去走”。</p><p>还有社长那种“如果出了什么问题我来兜底”的心态，真的让我很受鼓舞。</p><p>————两年前的采访中你说过“想和日高先生好好聊一聊”，实现了吗？</p><p>我觉得已经聊得很充分了。去年（2023年）3、4月的时候，我都不知道去了多少次社长家。比如工作快结束的时候就直接去他家，吃饭、聊天，然后再回家，这种情况经常发生。基本上一直都在聊音乐。</p><p>————SKY-HI说过的话中，让你最受益的是哪一点？</p><p>真的太多了，但如果要选一个的话，大概就是“所有的行为都伴随着责任”。哪怕是一句歌词，或者一篇Instagram的文字，只要一个字不一样，给人的印象就可能完全不同。自己觉得是好意说出来的话，也可能被理解成带有否定意味。“自由的背后伴随着责任”这件事，是我最近通过日高先生的言行慢慢意识到的。</p><blockquote><h3 id="from-sky-hi" tabindex="-1">from SKY-HI <a class="header-anchor" href="#from-sky-hi" aria-label="Permalink to &quot;from SKY-HI&quot;">​</a></h3><p>世界第一爱撒娇的boy，就是edhiii boi（笑）。也是我抱得最多的艺人（笑）。</p><p>只要给予足够的爱，他就能以更好的心态和动力去活动，而我对他投入的爱是没有上限的，所以在这点上完全不担心。对所有SOLO艺人来说都是如此，edhiii也逐渐把“作为一名艺人生活”这件事，当成理所当然的事情了。</p><p>这种自觉是形成气场的重要要素，实际上edhiii boi在舞台上展现出魅力的次数也越来越多。粉丝不断增加，自信也随之提升，真的非常棒。希望他在适当地撒娇的同时（？），继续很好地成长下去！</p></blockquote>',40)])])}const M=i(t,[["render",r]]);export{m as __pageData,M as default};
